import React, { useEffect, useState, Fragment } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const API = 'https://pizza-story-backend-u6n0.onrender.com';

const STEPS = [
  { key: 'pending',        label: 'התקבלה',  icon: '📋', desc: 'ממתין לאישור המטבח' },
  { key: 'preparing',      label: 'בהכנה',    icon: '👨‍🍳', desc: 'הפיצה שלך נאפית עכשיו' },
  { key: 'outForDelivery', label: 'בדרך',     icon: '🛵', desc: 'השליח בדרך אליך' },
  { key: 'completed',      label: 'הגיעה!',   icon: '✅', desc: 'תיאבון!' },
];

function stepIndex(status) {
  const idx = STEPS.findIndex(s => s.key === status);
  return idx === -1 ? 0 : idx;
}

export default function OrderTracker() {
  const [order, setOrder]   = useState(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  const fetchOrder = () => {
    if (!auth.phone) return;
    axios
      .get(`${API}/api/orders/current/${auth.phone}`)
      .then(res => setOrder(res.data))
      .catch(() => setOrder(null))
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    if (!auth.phone) { navigate('/login'); return; }
    fetchOrder();
    const id = setInterval(fetchOrder, 30000);
    return () => clearInterval(id);
  }, []);

  const currentStep = stepIndex(order?.status || 'pending');
  const progressPct = ((currentStep) / (STEPS.length - 1)) * 100;

  if (loading) {
    return (
      <div className="max-w-md mx-auto min-h-screen bg-gray-50 pb-20">
        <div className="bg-navy px-5 pt-5 pb-4">
          <h1 className="text-white text-xl font-black">מעקב הזמנה</h1>
        </div>
        <div className="flex flex-col items-center justify-center py-28">
          <div className="text-6xl mb-4 animate-pulse">🍕</div>
          <p className="text-gray-400">טוען...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto min-h-screen bg-gray-50 pb-20">

      {/* Navy Header */}
      <div className="bg-navy px-5 pt-5 pb-5">
        <h1 className="text-white text-xl font-black mb-0.5">מעקב הזמנה</h1>
        <p className="text-blue-200 text-xs">מתעדכן אוטומטית כל 30 שניות</p>
      </div>

      {!order ? (
        <div className="px-4 pt-8">
          <div className="bg-white rounded-2xl shadow-md p-8 text-center">
            <div className="text-7xl mb-4">🍕</div>
            <p className="text-xl font-black text-gray-800 mb-2">אין הזמנה פעילה</p>
            <p className="text-sm text-gray-400 mb-7">הזמנות האחרונות שלך יופיעו כאן לאחר שתזמינו</p>
            <button
              onClick={() => navigate('/')}
              className="bg-tomato text-white px-8 py-4 rounded-2xl font-black text-lg shadow-md hover:bg-red-700 transition active:scale-95"
            >
              🍕 הזמן עכשיו
            </button>
          </div>
        </div>
      ) : (
        <div className="px-4 pt-4 space-y-4">

          {/* Order Info Card */}
          <div className="bg-white rounded-2xl shadow-md p-4">
            <div className="flex justify-between items-center mb-1">
              <p className="text-gray-400 text-xs font-medium">
                הזמנה #{order.id?.slice(-6)?.toUpperCase()}
              </p>
              <p className="text-gray-400 text-xs">
                {order.createdAt
                  ? new Date(order.createdAt).toLocaleTimeString('he-IL', { hour: '2-digit', minute: '2-digit' })
                  : ''}
              </p>
            </div>
            <p className="font-black text-3xl text-tomato">{order.total}₪</p>
            <p className="text-gray-500 text-sm mt-1">
              🍕 {order.toppings?.length > 0 ? order.toppings.join(', ') : 'ללא תוספות'}
            </p>
          </div>

          {/* THE TRACKER — Domino's Pizza Tracker Style */}
          <div className="bg-white rounded-2xl shadow-md overflow-hidden">
            {/* Red top stripe */}
            <div className="bg-tomato px-5 py-3">
              <p className="text-white font-black text-base">🍕 Pizza Tracker</p>
              <p className="text-white/70 text-xs">
                {STEPS[currentStep].desc}
              </p>
            </div>

            <div className="px-5 py-6">
              {/* Progress Bar */}
              <div className="relative mb-8">
                {/* Background track */}
                <div className="absolute top-5 left-0 right-0 h-1.5 bg-gray-200 rounded-full" />
                {/* Filled track */}
                <div
                  className="absolute top-5 right-0 h-1.5 bg-tomato rounded-full transition-all duration-700"
                  style={{ width: `${progressPct}%`, left: 'auto', right: 0 }}
                />
                {/* Actually, let's do LTR for the progress to match left-to-right step order */}
                <div
                  className="absolute top-5 left-0 h-1.5 bg-tomato rounded-full transition-all duration-700"
                  style={{ width: `${progressPct}%` }}
                />

                {/* Step Circles */}
                <div className="relative flex justify-between">
                  {STEPS.map((step, idx) => {
                    const done    = idx <= currentStep;
                    const current = idx === currentStep;
                    return (
                      <div key={step.key} className="flex flex-col items-center" style={{ width: 64 }}>
                        <div
                          className={`w-10 h-10 rounded-full flex items-center justify-center text-lg border-2 transition-all duration-500 z-10 relative ${
                            done
                              ? 'bg-tomato border-tomato shadow-md'
                              : 'bg-white border-gray-200'
                          } ${current ? 'ring-4 ring-red-200 scale-110' : ''}`}
                        >
                          {step.icon}
                        </div>
                        <span
                          className={`text-xs mt-2 font-bold text-center leading-tight ${
                            done ? 'text-tomato' : 'text-gray-300'
                          }`}
                        >
                          {step.label}
                        </span>
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* Current Status Message */}
              <div
                className="rounded-xl p-4 text-center"
                style={{ background: 'rgba(227,24,55,0.06)' }}
              >
                <p className="text-gray-800 font-bold text-base">
                  {order.status === 'pending'        && '📋 ההזמנה שלך התקבלה! מועברת למטבח...'}
                  {order.status === 'preparing'      && '👨‍🍳 הפיצה שלך בתנור! עוד כמה דקות...'}
                  {order.status === 'outForDelivery' && '🛵 הפיצה יצאה ובדרך אליך!'}
                  {order.status === 'completed'      && '🎉 ההזמנה הגיעה! תיאבון!'}
                  {!order.status                     && '📋 ממתין לעדכון מהמטבח...'}
                </p>
                {order.status === 'outForDelivery' && (
                  <p className="text-gray-500 text-sm mt-1">זמן משוער: 15–25 דקות</p>
                )}
              </div>
            </div>
          </div>

          {/* Order Again button */}
          {order.status === 'completed' && (
            <button
              onClick={() => navigate('/')}
              className="w-full bg-navy text-white py-4 rounded-2xl font-black text-lg shadow-md hover:opacity-90 transition active:scale-95"
            >
              🍕 הזמן שוב
            </button>
          )}
        </div>
      )}
    </div>
  );
}
